class Stack:
    def __init__(self):
        self._items = []

    def push(self, val):
        self._items.append(val)

    def pop(self):
        return self._items.pop()

    def peek(self):
        return self._items[-1]

    def is_empty(self):
        return not self._items

from collections import deque

class Queue:
    def __init__(self):
        self._items = deque()

    def enqueue(self, val):
        self._items.append(val)

    def dequeue(self):
        return self._items.popleft()

    def peek(self):
        return self._items[0]

    def is_empty(self):
        return not self._items
